const input = $input.first().json || {};
const headers = input.headers || {};
const hasWebhookBody = !!input.body || Object.keys(headers).length > 0;

function pad(n) {
  return String(n).padStart(2, '0');
}

function toDateString(date) {
  return date.getUTCFullYear() + '-' + pad(date.getUTCMonth() + 1) + '-' + pad(date.getUTCDate());
}

function getKstNow() {
  const now = new Date();
  return new Date(now.getTime() + 9 * 60 * 60 * 1000);
}

function parseDate(value, fallback) {
  const text = String(value || '').trim();
  let parts;
  if (!/^\d{4}-\d{2}-\d{2}$/.test(text)) return fallback;
  parts = text.split('-');
  return new Date(Date.UTC(Number(parts[0]), Number(parts[1]) - 1, Number(parts[2])));
}

if (!hasWebhookBody) {
  const today = getKstNow();
  const completionTarget = new Date(today.getTime());
  const dormantTarget = new Date(today.getTime());
  completionTarget.setDate(completionTarget.getDate() - 1);
  dormantTarget.setDate(dormantTarget.getDate() - 30);

  return [{
    json: {
      _source: 'schedule',
      _mode: 'process',
      dry_run: false,
      today: toDateString(today),
      target_completion_date: toDateString(completionTarget),
      target_dormant_date: toDateString(dormantTarget),
      run_completion: true,
      run_dormant: true
    }
  }];
}

const body = input.body || {};
const authHeader = headers.authorization || headers.Authorization || '';
const token = typeof authHeader === 'string' && authHeader.indexOf('Bearer ') === 0 ? authHeader.substring(7).trim() : '';
const expectedToken = $env.ADMIN_API_TOKEN || '';
if (!token || !expectedToken || token !== expectedToken) {
  return [{ json: { _source: 'webhook', _mode: 'unauthorized' } }];
}

const today = parseDate(body.today, getKstNow());
const completionTarget = new Date(today.getTime());
const dormantTarget = new Date(today.getTime());
completionTarget.setDate(completionTarget.getDate() - 1);
dormantTarget.setDate(dormantTarget.getDate() - 30);

const only = String(body.only || 'all').trim().toLowerCase();
const dryRun = body.dry_run === true || String(body.dry_run || '').toLowerCase() === 'true' || String(body.mode || '').toLowerCase() === 'dry_run';

return [{
  json: {
    _source: 'webhook',
    _mode: 'process',
    dry_run: dryRun,
    today: toDateString(today),
    target_completion_date: toDateString(completionTarget),
    target_dormant_date: toDateString(dormantTarget),
    run_completion: only !== 'dormant',
    run_dormant: only !== 'completion'
  }
}];

return [{
  json: {
    success: false,
    error: {
      code: 'UNAUTHORIZED',
      message: '관리자 인증이 필요합니다.'
    },
    timestamp: new Date().toISOString()
  }
}];

const meta = $('Parse Trigger & Auth').first().json;
const completionRows = $('NocoDB Get Completion Targets').first().json.list || [];
const dormantRows = $('NocoDB Get Dormant Candidates').first().json.list || [];
const recentRows = $('NocoDB Get Recent Activity').first().json.list || [];
const classRows = $('NocoDB Get Classes').first().json.list || [];

function escapeHtml(str) {
  if (!str) return '';
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/\"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function memberKey(row) {
  return String(row.member_id || row.student_member_id || row.student_email || '').trim();
}

function appendFlag(text, flag) {
  const current = String(text || '').trim();
  if (!current) return flag;
  if (current.indexOf(flag) !== -1) return current;
  return current + ',' + flag;
}

function validEmail(email) {
  return String(email || '').indexOf('@') !== -1;
}

function getDateOnly(value) {
  return String(value || '').substring(0, 10);
}

function classMap(rows) {
  const map = {};
  rows.forEach(function(row) {
    if (row.class_id) {
      map[row.class_id] = row;
    }
  });
  return map;
}

function buildWrap(title, content) {
  return '<!DOCTYPE html><html lang="ko"><head><meta charset="UTF-8" /><meta name="viewport" content="width=device-width, initial-scale=1.0" /><title>' + title + '</title></head>'
    + '<body style="margin:0;padding:0;background:#f8f6f0;font-family:Pretendard,Apple SD Gothic Neo,Malgun Gothic,sans-serif;">'
    + '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="background:#f8f6f0;"><tr><td align="center" style="padding:24px 16px;">'
    + '<table width="600" cellpadding="0" cellspacing="0" border="0" style="max-width:600px;width:100%;background:#ffffff;border-radius:10px;overflow:hidden;box-shadow:0 2px 12px rgba(0,0,0,0.06);">'
    + '<tr><td style="padding:24px 32px;text-align:center;border-bottom:2px solid #b89b5e;">'
    + '<span style="font-size:22px;font-weight:700;color:#b89b5e;letter-spacing:2px;">PRESSCO21</span><br />'
    + '<span style="font-size:11px;color:#999999;letter-spacing:1px;">Forever and ever and Blooming</span>'
    + '</td></tr>'
    + content
    + '<tr><td style="padding:24px 32px;text-align:center;background:#faf8f3;border-top:1px solid #e8e4db;">'
    + '<p style="margin:0 0 8px;font-size:12px;color:#999999;">PRESSCO21 | foreverlove.co.kr</p>'
    + '<p style="margin:0;font-size:11px;color:#bbbbbb;">이 메일은 PRESSCO21 클래스 운영 안내 메일입니다.</p>'
    + '</td></tr></table></td></tr></table></body></html>';
}

function buildCompletionHtml(target) {
  const studentName = escapeHtml(target.student_name || '고객');
  const className = escapeHtml(target.class_name || '클래스');
  const classDate = escapeHtml(String(target.class_date || '').substring(0, 10));
  const detailUrl = 'https://foreverlove.co.kr/shop/page.html?id=2607&class_id=' + encodeURIComponent(target.class_id || '');
  const myPageUrl = 'https://foreverlove.co.kr/shop/page.html?id=2609';
  return buildWrap('PRESSCO21 수강 완료', ''
    + '<tr><td style="padding:36px 32px 32px;">'
    + '<p style="margin:0 0 18px;font-size:15px;color:#333333;line-height:1.7;"><strong style="color:#b89b5e;">' + studentName + '</strong>님, 수강을 마치셨습니다.</p>'
    + '<p style="margin:0 0 8px;font-size:15px;color:#333333;line-height:1.7;"><strong>' + className + '</strong> 수업이 완료되었습니다.</p>'
    + '<p style="margin:0 0 24px;font-size:14px;color:#555555;line-height:1.7;">' + classDate + ' 수업을 기준으로 후기 작성, 같은 강사의 다음 클래스 탐색, 재료 다시 보기를 이어갈 수 있도록 준비했습니다.</p>'
    + '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="background:#faf8f3;border:1px solid #e8e4db;border-radius:8px;margin-bottom:24px;">'
    + '<tr><td style="padding:20px 24px;">'
    + '<p style="margin:0 0 8px;font-size:14px;font-weight:700;color:#b89b5e;">지금 이어서 할 수 있는 일</p>'
    + '<p style="margin:0;font-size:13px;color:#666666;line-height:1.8;">1. 후기 남기기  2. 재료 다시 보기  3. 다음 수업 비교하기</p>'
    + '</td></tr></table>'
    + '<div style="text-align:center;margin-bottom:12px;"><a href="' + detailUrl + '" style="display:inline-block;background:#b89b5e;color:#ffffff;text-decoration:none;font-size:15px;font-weight:700;padding:14px 36px;border-radius:6px;">후기와 상세 보기</a></div>'
    + '<div style="text-align:center;"><a href="' + myPageUrl + '" style="display:inline-block;color:#7d9675;text-decoration:none;font-size:14px;font-weight:700;">내 수강 내역에서 이어보기</a></div>'
    + '</td></tr>');
}

function buildDormantHtml(target) {
  const studentName = escapeHtml(target.student_name || '고객');
  const className = escapeHtml(target.class_name || '클래스');
  const listUrl = 'https://foreverlove.co.kr/shop/page.html?id=2606';
  const myPageUrl = 'https://foreverlove.co.kr/shop/page.html?id=2609';
  return buildWrap('PRESSCO21 다시 보고 싶어요', ''
    + '<tr><td style="padding:36px 32px 32px;">'
    + '<p style="margin:0 0 18px;font-size:15px;color:#333333;line-height:1.7;"><strong style="color:#b89b5e;">' + studentName + '</strong>님, 다시 보고 싶어요.</p>'
    + '<p style="margin:0 0 8px;font-size:15px;color:#333333;line-height:1.7;">최근 참여하신 <strong>' + className + '</strong> 이후로 새로운 수업 소식이 준비되어 있습니다.</p>'
    + '<p style="margin:0 0 24px;font-size:14px;color:#555555;line-height:1.7;">전국 오프라인 클래스와 온라인 강의 중에서 지역과 카테고리를 골라 다시 탐색해보세요.</p>'
    + '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="background:#f7fbf5;border:1px solid #dfe9dc;border-radius:8px;margin-bottom:24px;">'
    + '<tr><td style="padding:20px 24px;">'
    + '<p style="margin:0 0 8px;font-size:14px;font-weight:700;color:#52794f;">다시 시작하기 좋은 방법</p>'
    + '<p style="margin:0;font-size:13px;color:#666666;line-height:1.8;">지역 필터로 가까운 수업을 찾거나, 입문 난이도 클래스로 다시 흐름을 이어보세요.</p>'
    + '</td></tr></table>'
    + '<div style="text-align:center;margin-bottom:12px;"><a href="' + listUrl + '" style="display:inline-block;background:#7d9675;color:#ffffff;text-decoration:none;font-size:15px;font-weight:700;padding:14px 36px;border-radius:6px;">다시 클래스 탐색하기</a></div>'
    + '<div style="text-align:center;"><a href="' + myPageUrl + '" style="display:inline-block;color:#b89b5e;text-decoration:none;font-size:14px;font-weight:700;">내 수강 내역 보기</a></div>'
    + '</td></tr>');
}

const classes = classMap(classRows);
const completionTargets = [];
const dormantTargets = [];
let completionRawCount = 0;
let dormantRawCount = 0;
let completionSkippedMissingEmail = 0;
let dormantSkippedMissingEmail = 0;
const recentMembers = {};
const dormantSeen = {};

recentRows.forEach(function(row) {
  const rowDate = getDateOnly(row.class_date);
  const key = memberKey(row);
  if (meta.run_dormant && key && rowDate > meta.target_dormant_date) recentMembers[key] = true;
});

completionRows.forEach(function(row) {
  const rowDate = getDateOnly(row.class_date);
  const email = String(row.student_email || '').trim();
  const classInfo = classes[row.class_id] || {};
  const emailSent = String(row.student_email_sent || '');
  if (!meta.run_completion || rowDate !== meta.target_completion_date) return;
  completionRawCount += 1;
  if (!validEmail(email)) {
    completionSkippedMissingEmail += 1;
    return;
  }
  if (emailSent.indexOf('COMPLETE_SENT') !== -1) return;
  completionTargets.push({
    record_id: row.Id || row.id || '',
    settlement_id: row.settlement_id || '',
    member_id: memberKey(row),
    student_name: row.student_name || '고객',
    student_email: email,
    class_id: row.class_id || '',
    class_name: row.class_name || classInfo.class_name || '클래스',
    class_date: row.class_date || '',
    current_email_sent: emailSent,
    new_email_sent: appendFlag(emailSent, 'COMPLETE_SENT'),
    subject: '[PRESSCO21] 수강 완료 축하드려요. 다음 흐름을 이어가세요',
    html: ''
  });
});

dormantRows.forEach(function(row) {
  const rowDate = getDateOnly(row.class_date);
  const email = String(row.student_email || '').trim();
  const key = memberKey(row);
  const classInfo = classes[row.class_id] || {};
  const emailSent = String(row.student_email_sent || '');
  if (!meta.run_dormant || rowDate !== meta.target_dormant_date) return;
  dormantRawCount += 1;
  if (!key || dormantSeen[key] || recentMembers[key]) return;
  if (!validEmail(email)) {
    dormantSkippedMissingEmail += 1;
    return;
  }
  if (emailSent.indexOf('DORMANT_30_SENT') !== -1) return;
  dormantSeen[key] = true;
  dormantTargets.push({
    record_id: row.Id || row.id || '',
    settlement_id: row.settlement_id || '',
    member_id: key,
    student_name: row.student_name || '고객',
    student_email: email,
    class_id: row.class_id || '',
    class_name: row.class_name || classInfo.class_name || '클래스',
    class_date: row.class_date || '',
    current_email_sent: emailSent,
    new_email_sent: appendFlag(emailSent, 'DORMANT_30_SENT'),
    subject: '[PRESSCO21] 다시 보고 싶어요. 다음 클래스를 골라보세요',
    html: ''
  });
});

completionTargets.forEach(function(target) { target.html = buildCompletionHtml(target); });
dormantTargets.forEach(function(target) { target.html = buildDormantHtml(target); });

return [{
  json: {
    ...meta,
    completion_raw_count: completionRawCount,
    completion_skipped_missing_email: completionSkippedMissingEmail,
    completion_count: completionTargets.length,
    dormant_raw_count: dormantRawCount,
    dormant_skipped_missing_email: dormantSkippedMissingEmail,
    dormant_count: dormantTargets.length,
    completion_targets: completionTargets,
    dormant_targets: dormantTargets,
    preview: {
      completion: completionTargets.slice(0, 5).map(function(item) {
        return {
          settlement_id: item.settlement_id,
          student_email: item.student_email,
          class_name: item.class_name,
          class_date: item.class_date
        };
      }),
      dormant: dormantTargets.slice(0, 5).map(function(item) {
        return {
          settlement_id: item.settlement_id,
          student_email: item.student_email,
          class_name: item.class_name,
          class_date: item.class_date
        };
      })
    },
    timestamp: new Date().toISOString()
  }
}];

const plan = $input.first().json;
return [{
  json: {
    success: true,
    data: {
      source: plan._source,
      dry_run: true,
      today: plan.today,
      target_completion_date: plan.target_completion_date,
      target_dormant_date: plan.target_dormant_date,
      completion_count: plan.completion_count,
      completion_raw_count: plan.completion_raw_count,
      completion_skipped_missing_email: plan.completion_skipped_missing_email,
      dormant_count: plan.dormant_count,
      dormant_raw_count: plan.dormant_raw_count,
      dormant_skipped_missing_email: plan.dormant_skipped_missing_email,
      preview: plan.preview
    },
    timestamp: new Date().toISOString()
  }
}];

const plan = $input.first().json;
return [{
  json: {
    success: true,
    data: {
      accepted: true,
      completion_count: plan.completion_count,
      completion_raw_count: plan.completion_raw_count,
      dormant_count: plan.dormant_count,
      dormant_raw_count: plan.dormant_raw_count,
      today: plan.today
    },
    timestamp: new Date().toISOString()
  }
}];

const plan = $input.first().json;
const dry = plan.dry_run ? 'DRY-RUN ' : '';
return [{
  json: {
    _telegramMessage: '*학생 리텐션 ' + dry + '실행*\n\n'
      + '기준일: ' + plan.today + '\n'
      + '수강 완료 축하 대상: ' + plan.completion_count + '건 (후보 ' + plan.completion_raw_count + ', 이메일 누락 ' + plan.completion_skipped_missing_email + ')\n'
      + '30일 휴면 대상: ' + plan.dormant_count + '건 (후보 ' + plan.dormant_raw_count + ', 이메일 누락 ' + plan.dormant_skipped_missing_email + ')\n'
      + '완료 기준일: ' + plan.target_completion_date + '\n'
      + '휴면 기준일: ' + plan.target_dormant_date
  }
}];

const plan = $input.first().json;
return (plan.completion_targets || []).map(function(item) {
  return { json: item };
});

const plan = $input.first().json;
return (plan.dormant_targets || []).map(function(item) {
  return { json: item };
});
